// Forge surface textures — seamless, tileable panel-fill materials (stone, wood),
// generated by codex and METHOD-VERIFIED via the shared codex-imagegen helper: a genuine
// generation emits an `image_generation_call` event in the session ROLLOUT log (NOT in
// `exec --json` stdout — see codex-imagegen.mjs). Each texture ships from the session's own
// generated_images/<thread_id>/ dir (race-free). See docs/kit-forge.md, ADR-0011/0014.
//
//   node frontend/scripts/forge-surface-texture.mjs [name...] --slot-prefix <slot> -- <upload options>
//
// These are TILES, so the mechanical check is wrap-seam error (right↔left, bottom↔top),
// not transparency. It's a WARN, not a hard gate — codex seamlessness is imperfect and
// we want to eyeball the look first; healing is a later pass once a material is chosen.
import { mkdtempSync, rmSync, readFileSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { CODEX, runCodex, imageGenVerdict, sessionImage } from './codex-imagegen.mjs';
import { optionValue, splitGeneratorArgs, uploadGeneratedCandidate } from './upload-generated-candidate.mjs';

// The shared shell palette (frontend/src/style.css tokens) so the materials harmonize
// with the dark low-glare app shell instead of fighting it.
const SPECS = [
  {
    name: 'stone-blue',
    material: 'a large weathered cool blue-grey stone surface — slate / bluestone, like a moonlit castle floor',
    palette: 'deep navy-slate #14222e and #0d1720 in the shadows, mid blue-grey #2a4150, cool steel highlights around #476171 to #5d7a8c, faint cooler speckle; overall desaturated and LOW-GLARE (this sits behind UI text)',
    notes: 'natural weathered slate — irregular mottling, a wandering network of fine hairline cracks, scattered pits and chips of varying size, occasional faint mineral veins, broad uneven patches of slightly lighter and darker stone; richly varied and NON-repeating across the whole surface',
  },
  {
    name: 'stone-grey',
    material: 'a large weathered grey granite / limestone surface — a medieval keep wall worn by age',
    palette: 'neutral granite greys: #2b2f33 and #23272b shadows, mid #3a4045 and #4a5258, soft #5b636a highlights, only the faintest cool tint; muted and matte',
    notes: 'natural weathered granite/limestone — uneven mottling and speckle, shallow erosion, scattered chips and pits, a few wandering cracks, faint lichen-dark and water-stained patches; varied and NON-repeating across the whole surface',
  },
  {
    name: 'wood-oak',
    material: 'a large aged oak timber surface — warm medieval planking, like a worn tavern table or hall floor',
    palette: 'warm browns: deep #2f2014 and #3f2a1c shadows, mid oak #5a3d28 and #6e4a2f, soft amber highlight #8a6238; muted, not orange, low-glare',
    notes: 'natural aged oak boards — long flowing grain that curves around several knots of different sizes, plank-to-plank colour and tone variation, small splits, nail marks and wear; organic and NON-repeating, never a uniform stripe pattern',
  },
  {
    name: 'wood-walnut',
    material: 'a large dark aged hardwood surface — walnut / smoked oak, richer and quieter than the oak',
    palette: 'deep cool-leaning browns: #1f140d and #2a1c12 shadows, mid #3a2a1e and #4a3424, restrained highlight #5e442e; deep, matte, low-glare',
    notes: 'natural aged walnut boards — rich flowing grain and figure, occasional knots, plank-to-plank tonal variation, subtle wear and patina; organic and NON-repeating across the whole surface',
  },
];

function prompt(spec, prior) {
  return `IMAGE-GENERATION task: create ONE PNG by GENERATING it with the built-in image_gen tool (the imagegen skill). Do NOT hand-draw it with code (PIL/Pillow, cairo, matplotlib, SVG, HTML/CSS, canvas), do NOT write a script, and do NOT crop or extract from any file — programmatic output is automatically rejected and you will be asked again.${prior ? `\n\nYOUR PREVIOUS ATTEMPT WAS REJECTED: ${prior}\n` : ''}

Generate a LARGE, RICH, NATURAL pixel-art SURFACE of ${spec.material}. This is a big, detailed, continuous surface that fills the whole canvas — NOT a small repeating tile and NOT a regular grid of identical units.

STYLE — the single most important requirement: detailed PIXEL ART in the spirit of a high-quality modern 16-bit game environment (Octopath Traveler, Eastward, Hyper Light Drifter ground/wall surfaces). A limited but rich, harmonious palette; fine yet clearly VISIBLE pixels; tasteful dithering for shading. It MUST read as crafted pixel art — NOT a photograph, NOT a smooth or painterly render, NOT a 3D render. No blur, no soft gradients, no anti-aliasing, no glossy highlights.

PALETTE (build the limited palette from these): ${spec.palette}.

NATURAL & ORGANIC — the second most important thing: a large weathered NATURAL surface with rich detail distributed UNEVENLY and NON-REPEATINGLY across the entire canvas — ${spec.notes}. It must read as a believable natural material, NOT a tile: no regular grid of identical blocks/bricks/planks, no repeating motif, no obvious symmetry. Vary the density and tone across the surface so different regions look different. Keep it dark and low-glare enough to sit behind off-white UI text.

Fill the entire canvas edge to edge with the material — fully opaque, no border, frame, vignette, or text.

Save it as ./${spec.name}.png in the current working directory, then stop.`;
}

// Wrap-seam error: how different are opposite edges (the seam you'd see when tiling).
// 0 = perfectly seamless; higher = more visible seam. WARN only. pngjs may be absent
// in a partial worktree node_modules — if so, skip silently (compute it later from
// the main checkout). Generation must not depend on it.
async function seamError(pngPath) {
  let PNG;
  try { ({ PNG } = await import('pngjs')); } catch { return null; }
  const p = PNG.sync.read(readFileSync(pngPath));
  const { width: w, height: h, data: d } = p;
  const px = (x, y) => { const i = (y * w + x) * 4; return [d[i], d[i + 1], d[i + 2]]; };
  const diff = (a, b) => (Math.abs(a[0] - b[0]) + Math.abs(a[1] - b[1]) + Math.abs(a[2] - b[2])) / 3;
  let lr = 0, tb = 0;
  for (let y = 0; y < h; y += 1) lr += diff(px(0, y), px(w - 1, y));
  for (let x = 0; x < w; x += 1) tb += diff(px(x, 0), px(x, h - 1));
  return { lr: +(lr / h).toFixed(1), tb: +(tb / w).toFixed(1), size: `${w}x${h}` };
}

async function forgeOne(spec, maxTries) {
  let prior = '';
  for (let attempt = 1; attempt <= maxTries; attempt += 1) {
    const work = mkdtempSync(join(tmpdir(), `surf-${spec.name}-`));
    try {
      const { out: jsonl } = await runCodex(work, prompt(spec, prior));
      // PRIMARY gate: the canonical image_generation_call event in the session rollout.
      const verdict = imageGenVerdict(jsonl);
      if (!verdict.ok) {
        console.log(`  ${spec.name} try ${attempt}: METHOD ✗ — ${verdict.reason}`);
        prior = 'the rollout shows you did NOT emit an image_generation_call — you hand-drew the PNG in code (PIL/canvas/SVG). You MUST use the built-in image_gen tool (imagegen skill) to GENERATE the texture as a real bitmap.';
        continue;
      }
      // Ship the session's OWN model output (race-free), NOT codex's racy workspace copy.
      const shipped = sessionImage(verdict.tid);
      if (!shipped) {
        console.log(`  ${spec.name} try ${attempt}: generated but no ig_*.png under generated_images/${verdict.tid} — retrying`);
        prior = 'you generated an image but it could not be located in the default image output folder; generate again and leave the output there.';
        continue;
      }
      const seam = await seamError(shipped);
      const seamStr = seam ? `(${seam.size}) seam L↔R=${seam.lr} T↔B=${seam.tb}` : '(seam skipped — no pngjs)';
      const provenance = join(work, 'provenance.json');
      writeFileSync(provenance, `${JSON.stringify({ generator: 'forge-surface-texture', threadId: verdict.tid, seam }, null, 2)}\n`);
      uploadGeneratedCandidate(shipped, [...uploadArgs, '--provenance-json', provenance], `${slotPrefix}/${spec.name}.png`);
      console.log(`  ${spec.name} try ${attempt}: image_generation_call ✓ · ${seamStr} -> ${slotPrefix}/${spec.name}.png`);
      return { name: spec.name, pass: true, tries: attempt, seam, tid: verdict.tid };
    } finally {
      rmSync(work, { recursive: true, force: true });
    }
  }
  return { name: spec.name, pass: false, tries: maxTries };
}

const { toolArgs, uploadArgs } = splitGeneratorArgs(process.argv.slice(2));
const slotPrefix = optionValue(toolArgs, '--slot-prefix').replace(/\/+$/, '');
if (!slotPrefix || !uploadArgs.length) throw new Error('forge-surface-texture requires --slot-prefix and live-media options after --');
const prefixIndex = toolArgs.indexOf('--slot-prefix');
const argv = toolArgs.filter((_, index) => index !== prefixIndex && index !== prefixIndex + 1);
const flag = (n, def) => { const i = argv.indexOf(n); return i >= 0 ? argv[i + 1] : def; };
const n = Math.max(1, parseInt(flag('--n', '4'), 10));
const maxTries = Math.max(1, parseInt(flag('--tries', '2'), 10));
const names = argv.filter((a) => !a.startsWith('--') && !['--n', '--tries'].includes(argv[argv.indexOf(a) - 1]));
const queue = argv.includes('--all') || !names.length ? SPECS : SPECS.filter((s) => names.includes(s.name));

console.log(`forge-surface-texture: ${queue.length} tile(s), concurrency ${n}, up to ${maxTries} tries\n  codex: ${CODEX}\n`);
let i = 0; const results = [];
const worker = async () => { while (i < queue.length) { const s = queue[i]; i += 1; results.push(await forgeOne(s, maxTries)); } };
await Promise.all(Array.from({ length: Math.min(n, queue.length) }, worker));
const ok = results.filter((r) => r.pass).length;
console.log(`\n==== ${ok}/${results.length} forged ====`);
for (const r of results.filter((r) => r.pass)) console.log(`  ${r.name}: ${r.seam ? `seam L↔R=${r.seam.lr} T↔B=${r.seam.tb}` : 'forged (seam check skipped)'}`);
if (ok < results.length) console.log('  FAILED:', results.filter((r) => !r.pass).map((r) => r.name).join(', '));
